/* fed_admit_with_qc_proof -- hardened admission with caller-supplied PoW AND a
 * HotStuff quorum certificate (the 4th gate, gospel L24432).
 *
 * packed_meta layout:
 *   bits 32..63 : tier id (0 = planetary, 1 = galactic, 2 = sovereign)
 *   bits  0..31 : minimum sybil score required for admission
 *
 * Parameters: node_id, pow_nonce, packed_meta (above), qc_ptr (-> a HotStuff QC
 * buffer), qc_len (caller-supplied byte length of the qc_ptr buffer).
 *
 * QC wire format: [0..32) block_mhash, [32..40) view, [40..44) n_sigs (LE u32),
 * [44..) n_sigs*64 bytes of Ed25519 signatures.  Minimum valid length = 44.
 * qc_len must be >= 44 + n_sigs*64.  n_sigs is bounded to HS_MAX_PEERS (64)
 * which prevents u32 wrap in the length computation and confines key-table
 * indexing inside HS_PEER_KEYS[2048].
 *
 * Behavior:
 *   1. Null-check qc_ptr; reject qc_len < 44 (structural minimum).
 *   2. Read n_sigs from qc[40..44]; reject n_sigs > HS_MAX_PEERS.
 *   3. Reject qc_len < 44 + n_sigs*64 (buffer too short for declared sigs).
 *   4. Materialize node_id as a 32-byte peer-id buffer (sealed projection).
 *   5. Resolve PoW difficulty (bits) from tier; reject unknown tiers.
 *   6. Verify pow_nonce via fed_sybil_pow_verify at the tier-required bits.
 *   7. Read sybil score; require score >= threshold (low 32 of packed_meta).
 *   8. Verify the HotStuff QC (>= 2f+1 Ed25519 sigs) via hs_verify_qc; checked
 *      last so a failing sybil/pow/score gate is reported first.
 *   9. On success, dispatch to fed_admit_to_planetary using slot 0.
 *
 * Returns FED_ADMIT_OK (0) on success, or a negative error code.
 */
fn fed_admit_with_qc_proof(node_id: u64, pow_nonce: u64, packed_meta: u64, qc_ptr: *u8, qc_len: u32) -> i32 @export {
    let n_l : u64 = node_id
    let w_l : u64 = pow_nonce
    let m_l : u64 = packed_meta
    let ql_l : u32 = qc_len
    if (qc_ptr as u64) == 0u64 { return FED_ADMIT_E_NULL }
    /* Gate 0: structural minimum -- cannot read n_sigs without 44 bytes. */
    if ql_l < 44u32 { return FED_ADMIT_E_QC }
    /* Gate 1: read n_sigs, bound to HS_MAX_PEERS (64) -- prevents u32 wrap
     * in 44+n_sigs*64 and keeps HS_PEER_KEYS[] index in-range. */
    let qp : *u8 = qc_ptr
    let n_sigs : u32 = (qp[40u64] as u32) | ((qp[41u64] as u32) << 8u32) | ((qp[42u64] as u32) << 16u32) | ((qp[43u64] as u32) << 24u32)
    if n_sigs > 64u32 { return FED_ADMIT_E_QC }
    /* Gate 2: buffer must cover all declared signatures. */
    if ql_l < 44u32 + n_sigs * 64u32 { return FED_ADMIT_E_QC }
    let tier      : u32 = ((m_l >> 32u64) & 0xFFFFFFFFu64) as u32
    let threshold : u64 = m_l & 0xFFFFFFFFu64
    let bits      : u32 = _fed_admit_pow_bits_for_tier(tier)
    if bits == 0u32 { return FED_ADMIT_E_TIER_RANGE }
    _fed_admit_pack_node_id(n_l)
    let buf_addr : u64 = (&FED_ADMIT_NODE_ID_BUF) as u64
    if fed_sybil_pow_verify(buf_addr, w_l, bits) != 1u8 { return FED_ADMIT_E_POW }
    let score : u64 = fed_sybil_score(buf_addr)
    if score < threshold { return FED_ADMIT_E_SCORE }
    /* 4th gate (gospel L24432): the admission decision must be backed by a
     * HotStuff quorum certificate (>= 2f+1 verified Ed25519 signatures). */
    if hs_verify_qc(qp, ql_l) != 1u8 { return FED_ADMIT_E_QC }
    let rc : i32 = fed_admit_to_planetary(0u32, buf_addr)
    if rc != FED_ADMIT_OK { return rc }
    return FED_ADMIT_OK
}

/* QC-gated cross-tier anchor (gospel L24432): the Tier-3 / Bedrock cross-tier
 * anchor must be backed by a HotStuff quorum certificate over the anchor
 * decision.  qc_len is the caller-supplied byte length of qc_ptr.
 * Three layered guards before any QC indexing:
 *   (1) qc_len < 44  -- structural minimum (n_sigs field not yet readable);
 *   (2) n_sigs > 64  -- tighter than 0xFFFF; matches HS_MAX_PEERS ceiling,
 *                       prevents u32 wrap in 44+n_sigs*64;
 *   (3) qc_len < 44 + n_sigs*64 -- buffer does not cover declared sigs. */
fn fed_seal_anchor_with_qc(child_tier: u32, child_root_ptr: u64, parent_tier: u32, parent_root_ptr: u64, qc_ptr: *u8, qc_len: u32) -> i32 @export {
    let ql_l : u32 = qc_len
    if (qc_ptr as u64) == 0u64 { return FED_SEAL_E_NULL }
    /* Gate 0: structural minimum -- cannot read n_sigs without 44 bytes. */
    if ql_l < 44u32 { return FED_SEAL_E_QC }
    let qp : *u8 = qc_ptr
    let n_sigs : u32 = (qp[40u64] as u32) | ((qp[41u64] as u32) << 8u32) | ((qp[42u64] as u32) << 16u32) | ((qp[43u64] as u32) << 24u32)
    /* Gate 1: bound to HS_MAX_PEERS (64) -- tighter than the old 0xFFFF,
     * prevents u32 wrap and confines HS_PEER_KEYS[] indexing. */
    if n_sigs > 64u32 { return FED_SEAL_E_QC }
    /* Gate 2: buffer must cover all declared signatures. */
    if ql_l < 44u32 + n_sigs * 64u32 { return FED_SEAL_E_QC }
    if hs_verify_qc(qp, ql_l) != 1u8 { return FED_SEAL_E_QC }
    return fed_seal_anchor(child_tier, child_root_ptr, parent_tier, parent_root_ptr)
}

/* Pass the full 32-byte gen_root buffer; qc_len=32 < 44 triggers the
 * minimum-length guard and returns FED_ADMIT_E_QC (-7) BEFORE the PoW
 * check.  To keep this test on the PoW rejection path (E_POW = -4),
 * supply a 44-byte dummy QC so the length guard passes; PoW fires first
 * for nonce=0, so E_POW is still the result. */
let dummy_qc : *u8 = malloc(44u64)
if dummy_qc as u64 == 0u64 { return 6u64 }
let mut dq : u64 = 0u64
while dq < 44u64 { dummy_qc[dq] = 0u8  dq = dq + 1u64 }
let pow_rc : i32 = fed_admit_with_qc_proof(0xC0FFEEu64, 0u64, PACKED_META_PLANETARY, dummy_qc, 44u32)
free(dummy_qc)

/* C:\Users\Edwin Boston\OneDrive\Desktop\III\STDLIB\corpus\420_fed_qc_len_guard.iii
 *
 * III conformance corpus 420 -- QC minimum-length guard for fed_admit and fed_seal.
 *
 * Proves the fix FIRES on bad input (negative cases) and passes on good input.
 *
 * Negative cases (proving the guard):
 *   N1: fed_admit_with_qc_proof with qc_len=0  -> FED_ADMIT_E_QC (-7)
 *   N2: fed_admit_with_qc_proof with qc_len=10 -> FED_ADMIT_E_QC (-7)
 *   N3: fed_admit_with_qc_proof with qc_len=43 -> FED_ADMIT_E_QC (-7)
 *   N4: fed_seal_anchor_with_qc  with qc_len=0  -> FED_SEAL_E_QC  (-5)
 *   N5: fed_seal_anchor_with_qc  with qc_len=10 -> FED_SEAL_E_QC  (-5)
 *   N6: fed_seal_anchor_with_qc  with qc_len=43 -> FED_SEAL_E_QC  (-5)
 *   N7: fed_admit_with_qc_proof with a 256-byte QC where n_sigs=0xFFFFFFFF
 *       (n_sigs > 64 bound fires) -> FED_ADMIT_E_QC (-7)
 *   N8: fed_seal_anchor_with_qc  with a 256-byte QC where n_sigs=0xFFFFFFFF
 *       -> FED_SEAL_E_QC (-5)
 *
 * Positive case:
 *   P1: fed_admit_with_qc_proof qc_len=44 (minimum structural, n_sigs=0)
 *       -> reaches PoW check; nonce=0 fails -> FED_ADMIT_E_POW (-4), NOT E_QC.
 *       This proves the length-44 path passes the guard (PoW is checked after).
 *
 * Exit codes:
 *   99 = full pass
 *    1 = malloc failed
 *    2..9 = negative case NX did not return expected error
 *   10 = positive case P1 did not return E_POW (guard incorrectly fired or
 *        some other path failed)
 */
module corpus_420

extern @abi(c-msvc-x64) fn malloc(n: u64) -> *u8 from "msvcrt"
extern @abi(c-msvc-x64) fn free(p: *u8) -> u64 from "msvcrt"

extern @abi(c-msvc-x64) fn calculus_init() -> i32 from "calculus_v1.iii"
extern @abi(c-msvc-x64) fn proof_init() -> i32 from "irreducibility_proof.iii"
extern @abi(c-msvc-x64) fn fed_sybil_clear_all() -> i32 from "fed_sybil.iii"
extern @abi(c-msvc-x64) fn fed_eclipse_clear() -> i32 from "fed_eclipse.iii"
extern @abi(c-msvc-x64) fn fed_seal_clear() -> i32 from "fed_seal.iii"
extern @abi(c-msvc-x64) fn hs_init(node_id: u32, peers: *u8, n_peers: u32) -> i32 from "hotstuff.iii"

extern @abi(c-msvc-x64) fn fed_admit_with_qc_proof(node_id: u64, pow_nonce: u64, packed_meta: u64, qc_ptr: *u8, qc_len: u32) -> i32 from "fed_admit.iii"
extern @abi(c-msvc-x64) fn fed_seal_anchor_with_qc(child_tier: u32, child_root_ptr: u64, parent_tier: u32, parent_root_ptr: u64, qc_ptr: *u8, qc_len: u32) -> i32 from "fed_seal.iii"

/* FED_ADMIT_E_QC = -7, FED_ADMIT_E_POW = -4 (redeclared -- no cross-.iii const import) */
const FA_E_QC  : i32 = -7i32
const FA_E_POW : i32 = -4i32
const FS_E_QC  : i32 = -5i32

/* Packed meta for planetary tier, zero score threshold -- PoW check fires
 * before QC when qc_len passes the structural gate. */
const PACKED_META_0 : u64 = 0u64

/* 256-byte scratch buffer shared across tests.  We overwrite specific bytes
 * per test; zero the whole buffer at the start of each scenario. */
var BUF256 : [u8; 256]
var PEER_KEYS : [u8; 32]
var CHILD_ROOT : [u8; 32]
var PARENT_ROOT : [u8; 32]

fn _zero256() -> u32 {
    let mut i : u64 = 0u64
    while i < 256u64 { BUF256[i] = 0u8  i = i + 1u64 }
    return 0u32
}

fn _set_n_sigs(v: u32) -> u32 {
    BUF256[40u64] = (v & 0xFFu32) as u8
    BUF256[41u64] = ((v >> 8u32)  & 0xFFu32) as u8
    BUF256[42u64] = ((v >> 16u32) & 0xFFu32) as u8
    BUF256[43u64] = ((v >> 24u32) & 0xFFu32) as u8
    return 0u32
}

fn main() -> u64 {
    /* Bootstrap: same pattern as corpus 240. */
    if calculus_init() != 0i32 { return 1u64 }
    if proof_init() != 0i32 { return 1u64 }
    fed_sybil_clear_all()
    fed_eclipse_clear()
    fed_seal_clear()
    /* hs_init with 1 zero-keyed peer so HS_INITED=1 (needed for hs_verify_qc
     * to run; the QC will fail sig verification, but we need to get past the
     * INITED guard in the positive-case path). */
    let mut zi : u64 = 0u64
    while zi < 32u64 { PEER_KEYS[zi] = 0u8  zi = zi + 1u64 }
    hs_init(0u32, (&PEER_KEYS as u64) as *u8, 1u32)

    /* --- Negative cases: short qc_len must return E_QC without reading OOB. --- */
    let buf_p : *u8 = (&BUF256 as u64) as *u8
    _zero256()

    /* N1: qc_len = 0 -> FED_ADMIT_E_QC */
    if fed_admit_with_qc_proof(0x1u64, 0u64, PACKED_META_0, buf_p, 0u32) != FA_E_QC { return 2u64 }

    /* N2: qc_len = 10 -> FED_ADMIT_E_QC */
    if fed_admit_with_qc_proof(0x1u64, 0u64, PACKED_META_0, buf_p, 10u32) != FA_E_QC { return 3u64 }

    /* N3: qc_len = 43 (one short of minimum) -> FED_ADMIT_E_QC */
    if fed_admit_with_qc_proof(0x1u64, 0u64, PACKED_META_0, buf_p, 43u32) != FA_E_QC { return 4u64 }

    /* N4: fed_seal qc_len = 0 -> FED_SEAL_E_QC */
    let mut ci : u64 = 0u64
    while ci < 32u64 { CHILD_ROOT[ci] = (ci + 1u64) as u8  PARENT_ROOT[ci] = (ci + 50u64) as u8  ci = ci + 1u64 }
    if fed_seal_anchor_with_qc(2u32, (&CHILD_ROOT as u64), 4u32, (&PARENT_ROOT as u64), buf_p, 0u32) != FS_E_QC { return 5u64 }

    /* N5: fed_seal qc_len = 10 -> FED_SEAL_E_QC */
    if fed_seal_anchor_with_qc(2u32, (&CHILD_ROOT as u64), 4u32, (&PARENT_ROOT as u64), buf_p, 10u32) != FS_E_QC { return 6u64 }

    /* N6: fed_seal qc_len = 43 -> FED_SEAL_E_QC */
    if fed_seal_anchor_with_qc(2u32, (&CHILD_ROOT as u64), 4u32, (&PARENT_ROOT as u64), buf_p, 43u32) != FS_E_QC { return 7u64 }

    /* N7: n_sigs overflow -- n_sigs = 0xFFFFFFFF in a 256-byte buffer;
     * qc_len=256 passes the minimum check, then n_sigs > 64 fires. */
    _zero256()
    _set_n_sigs(0xFFFFFFFFu32)
    if fed_admit_with_qc_proof(0x1u64, 0u64, PACKED_META_0, buf_p, 256u32) != FA_E_QC { return 8u64 }

    /* N8: same for fed_seal. */
    if fed_seal_anchor_with_qc(2u32, (&CHILD_ROOT as u64), 4u32, (&PARENT_ROOT as u64), buf_p, 256u32) != FS_E_QC { return 9u64 }

    /* --- Positive case P1: qc_len=44 passes structural gate; PoW fires. ---
     * n_sigs=0 (BUF256 zeroed) -> 44+0*64=44 byte check passes; PoW with
     * nonce=0 for node_id=0x1 fails the 32-bit leading-zero requirement ->
     * FED_ADMIT_E_POW.  This proves the guard does NOT over-fire on valid
     * structural inputs. */
    _zero256()
    if fed_admit_with_qc_proof(0x1u64, 0u64, PACKED_META_0, buf_p, 44u32) != FA_E_POW { return 10u64 }

    return 99u64
}
